import{_ as a,o as s,c as e,a2 as t}from"./chunks/framework.wSsqAhVZ.js";const r=JSON.parse('{"title":"回溯算法总结","description":"","frontmatter":{},"headers":[],"relativePath":"go-code-thoughts/8_backtracking/13_简单总结.md","filePath":"go-code-thoughts/8_backtracking/13_简单总结.md","lastUpdated":1784004070000}'),p={name:"go-code-thoughts/8_backtracking/13_简单总结.md"};function l(h,i,n,d,o,c){return s(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="回溯算法总结" tabindex="-1">回溯算法总结 <a class="header-anchor" href="#回溯算法总结" aria-label="Permalink to &quot;回溯算法总结&quot;">​</a></h1><p>原笔记写于 2025 年 8 月 2 日下午。 这一阶段主要把组合、分割、子集、排列和去重问题串了一遍。</p><p>回溯本质上是一种有组织的暴力枚举。</p><p>它通常可以抽象为一棵决策树。 在这棵树上，最核心的动作是：</p><ol><li>做出选择。</li><li>递归进入下一层。</li><li>撤销选择。</li></ol><p>也就是常见的回溯三部曲。</p><h2 id="组合和子集模型" tabindex="-1">组合和子集模型 <a class="header-anchor" href="#组合和子集模型" aria-label="Permalink to &quot;组合和子集模型&quot;">​</a></h2><p>组合和子集问题的共同点是顺序不重要。</p><p><code>[1, 2]</code> 和 <code>[2, 1]</code> 被视为同一种结果。</p><h3 id="基础组合" tabindex="-1">基础组合 <a class="header-anchor" href="#基础组合" aria-label="Permalink to &quot;基础组合&quot;">​</a></h3><p>为了避免重复选择， 使用 <code>startIndex</code> 控制下一层从哪里开始。</p><p>选择 <code>i</code> 后， 下一层递归从 <code>i + 1</code> 开始。</p><h3 id="组合总和-i" tabindex="-1">组合总和 I <a class="header-anchor" href="#组合总和-i" aria-label="Permalink to &quot;组合总和 I&quot;">​</a></h3><p>如果元素可以重复使用， 递归时下一层继续从 <code>i</code> 开始。</p><p>这表示当前元素可以在后续继续被选择。</p><h3 id="子集" tabindex="-1">子集 <a class="header-anchor" href="#子集" aria-label="Permalink to &quot;子集&quot;">​</a></h3><p>子集问题中， 决策树上的每一个节点都是答案。</p><p>所以使用沿途收集： 进入递归函数时就先收集当前 <code>path</code>。</p><h3 id="组合和子集去重" tabindex="-1">组合和子集去重 <a class="header-anchor" href="#组合和子集去重" aria-label="Permalink to &quot;组合和子集去重&quot;">​</a></h3><p>当输入中有重复元素， 但结果不能重复时， 常用做法是：</p><ol><li>先排序。</li><li>在同一层跳过重复元素。</li></ol><p>典型条件是：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> start </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nums[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nums[i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    continue</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>这个条件处理的是树层去重。</p><h2 id="排列模型" tabindex="-1">排列模型 <a class="header-anchor" href="#排列模型" aria-label="Permalink to &quot;排列模型&quot;">​</a></h2><p>排列问题的核心是顺序重要。</p><p><code>[1, 2]</code> 和 <code>[2, 1]</code> 是不同结果。</p><p>因此排列问题不能用 <code>startIndex</code> 限制向后选择。 每一层的 <code>for</code> 循环都要从 <code>0</code> 开始。</p><h3 id="全排列-i" tabindex="-1">全排列 I <a class="header-anchor" href="#全排列-i" aria-label="Permalink to &quot;全排列 I&quot;">​</a></h3><p>为了避免同一条路径中重复使用元素， 需要一个已用清单。</p><p>可以用 <code>used []bool</code> 或 <code>map</code> 记录当前路径里哪些元素已经被使用。</p><h3 id="全排列-ii" tabindex="-1">全排列 II <a class="header-anchor" href="#全排列-ii" aria-label="Permalink to &quot;全排列 II&quot;">​</a></h3><p>有重复元素的全排列需要更细的去重：</p><ol><li>先排序。</li><li>使用 <code>used []bool</code> 按位置记录。</li><li>先跳过已经使用的位置。</li><li>再跳过重复元素造成的同层重复分支。</li></ol><p>核心条件是：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nums[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nums[i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> !</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">used[i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    continue</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="分割模型" tabindex="-1">分割模型 <a class="header-anchor" href="#分割模型" aria-label="Permalink to &quot;分割模型&quot;">​</a></h2><p>分割问题的核心是把一个整体切成几块。</p><p>例如：</p><ul><li>分割回文串。</li><li>复原 IP 地址。</li></ul><p>这类题里， <code>for</code> 循环的 <code>i</code> 通常表示切割点。</p><p>当前切出来的片段是：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s[startIndex : i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>递归时从 <code>i + 1</code> 开始继续处理剩余部分。</p><p>分割问题的难点通常在合法性校验： 例如判断回文串，或判断 IP 段是否在 <code>0</code> 到 <code>255</code> 范围内。</p><h2 id="快速判断" tabindex="-1">快速判断 <a class="header-anchor" href="#快速判断" aria-label="Permalink to &quot;快速判断&quot;">​</a></h2><p>遇到组合或子集问题： 顺序不重要，优先考虑 <code>startIndex</code>。</p><p>遇到排列问题： 顺序重要，<code>for</code> 循环通常从 <code>0</code> 开始，并配合 <code>used</code>。</p><p>遇到分割问题： 把 <code>for</code> 循环里的 <code>i</code> 理解为切割点。</p><p>题目说元素可以重复使用： 递归传 <code>i</code>，而不是 <code>i + 1</code>。</p><p>题目说输入有重复但解集不能重复： 先考虑排序，再做树层去重。</p><p>题目不能排序： 例如递增子序列，需要用每层 <code>map</code> 记录本层已经使用过的数字。</p><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><p>回溯题的关键不是死记模板， 而是判断当前题目属于哪种决策树。</p><p>先分清组合、子集、排列、分割， 再决定结果收集位置、下一层起点、去重方式和剪枝条件。</p>`,55)])])}const g=a(p,[["render",l]]);export{r as __pageData,g as default};
